/* Codigo correcto, setInterval ////////////////////////////////////////////////////////////////////////////////*/  

function porcentajes(){
const porcentajes = [30, 35, 40, 30, 30, 30, 30];
const ids = ["Numb1", "Numb2", "Numb3", "Numb4", "Numb5", "Numb6", "Numb7"];
const variablescss = ["--varl1", "--varl2", "--varl3", "--varl4", "--varl5", "--varl6", "--varl7"];

var porcentaje =  0;
var vcss= 0;

ids.forEach(id =>{
  let elemento = porcentajes[porcentaje];
  let elementocss = variablescss[vcss];
  vcss+=1;
  porcentaje+=1;
  console.log(id + " " +elemento+"% "+elementocss);
  
  //Regla de tres para convertir porcentaje a grados
  var equivalencia = 360*elemento/100;

  //Define en la variable el dato del keyframe
  document.documentElement.style.setProperty(elementocss, equivalencia+"deg");
  
  console.log(id+ " "+equivalencia+" deg");
  var a = getComputedStyle(document.documentElement).getPropertyValue(elementocss);
  console.log(id+" "+a);
  //document.getElementById(id).style.animationDuration=4;

  let counter = 0;
  setInterval(()=>{
  if( counter== elemento){
    clearInterval();
  }else{
    counter+=1;
    document.getElementById(id).innerText=counter + "%"; //Dentro del setInterval deja hacer modificaciones al DOM
  }
  }, 80);
});
}

//porcentajes();
window.addEventListener("load", porcentajes);